Here's the refactored version using async/await:

```javascript
async function getUser(id) {
  try {
    const rows = await db.query('SELECT * FROM users WHERE id = ?', [id]);

    if (!rows.length) {
      throw new Error('Not found');
    }

    return rows[0];
  } catch (err) {
    throw err;
  }
}
```

Or, since the `catch` block is just re-throwing the error, you can simplify it to:

```javascript
async function getUser(id) {
  const rows = await db.query('SELECT * FROM users WHERE id = ?', [id]);

  if (!rows.length) {
    throw new Error('Not found');
  }

  return rows[0];
}
```

**Note:** This assumes that `db.query` returns a Promise. If your database library doesn't support Promises natively, you'll need to promisify it first using `util.promisify`:

```javascript
const util = require('util');
const query = util.promisify(db.query.bind(db));

async function getUser(id) {
  const rows = await query('SELECT * FROM users WHERE id = ?', [id]);

  if (!rows.length) {
    throw new Error('Not found');
  }

  return rows[0];
}
```

**Usage example:**

```javascript
// With async/await
try {
  const user = await getUser(123);
  console.log(user);
} catch (err) {
  console.error('Error:', err.message);
}

// Or with .then/.catch
getUser(123)
  .then(user => console.log(user))
  .catch(err => console.error('Error:', err.message));
```
